import{_ as o,c as a,o as t,ag as r}from"./chunks/framework.Dj4VfQLU.js";const m=JSON.parse('{"title":"Deployment Options Overview","description":"","frontmatter":{},"headers":[],"relativePath":"deployment-options-overview.md","filePath":"deployment-options-overview.md"}'),n={name:"deployment-options-overview.md"};function i(l,e,s,p,d,c){return t(),a("div",null,e[0]||(e[0]=[r('<h1 id="deployment-options-overview" tabindex="-1">Deployment Options Overview <a class="header-anchor" href="#deployment-options-overview" aria-label="Permalink to &quot;Deployment Options Overview&quot;">​</a></h1><p>BetterTaxi supports flexible deployment strategies depending on your goals, technical expertise, and infrastructure preferences.</p><p>We officially recommend using our <strong>Docker-based deployment script</strong>, which provides a fast and production-ready installation experience on your own server.</p><h2 id="🚀-recommended-docker-based-deployment" tabindex="-1">🚀 Recommended: Docker-Based Deployment <a class="header-anchor" href="#🚀-recommended-docker-based-deployment" aria-label="Permalink to &quot;🚀 Recommended: Docker-Based Deployment&quot;">​</a></h2><p>Our automated <code>install.sh</code> script pulls all necessary Docker images and services, including:</p><ul><li>Backend APIs</li><li>Admin panel (as a Flutter web app)</li><li>Rider app (as a Flutter web app)</li><li>MySQL, Redis, NGINX</li></ul><p>This setup is ideal for most buyers and is <strong>officially supported</strong>.</p><p>▶️ <strong>Start here:</strong> <a href="./server-side-installation-docker-mode.html">Server-Side Installation (Docker Mode)</a></p><blockquote><p>💡 We recommend using an unmanaged VPS provider like <strong>Hetzner</strong> or <strong>DigitalOcean</strong> for optimal performance and control.</p></blockquote><h2 id="⚙️-alternative-installation-methods" tabindex="-1">⚙️ Alternative Installation Methods <a class="header-anchor" href="#⚙️-alternative-installation-methods" aria-label="Permalink to &quot;⚙️ Alternative Installation Methods&quot;">​</a></h2><h3 id="source-code-installation-docker-compose" tabindex="-1">Source Code Installation (Docker Compose) <a class="header-anchor" href="#source-code-installation-docker-compose" aria-label="Permalink to &quot;Source Code Installation (Docker Compose)&quot;">​</a></h3><p>Build from source code while maintaining containerization benefits:</p><ul><li>Builds all services from source using Docker Compose</li><li>Allows full backend customization</li><li>Maintains reproducible containerized deployments</li><li>Ideal for developers who need code-level control</li></ul><p>▶️ <strong>Start here:</strong> <a href="./server-side-installation-source-mode.html">Source Code Installation Guide (Docker Compose)</a></p><h3 id="manual-installation-advanced" tabindex="-1">Manual Installation (Advanced) <a class="header-anchor" href="#manual-installation-advanced" aria-label="Permalink to &quot;Manual Installation (Advanced)&quot;">​</a></h3><p>Manual server-side setup (without Docker) is possible for experienced developers who prefer custom environments or full control over services.</p><ul><li>Requires setting up Node.js, databases, and NX-based workspace</li><li>Not officially supported for production by our team</li></ul><p>▶️ <strong>Start here:</strong> <a href="./server-side-installation-dev-mode.html">Server-Side Installation (Dev Mode)</a></p><blockquote><p>⚠️ Note: We cannot provide technical support for issues arising from manual installation paths.</p></blockquote><h2 id="📱-mobile-app-deployment" tabindex="-1">📱 Mobile App Deployment <a class="header-anchor" href="#📱-mobile-app-deployment" aria-label="Permalink to &quot;📱 Mobile App Deployment&quot;">​</a></h2><p>To fully launch BetterTaxi, you’ll also need to publish the <strong>Rider</strong> and <strong>Driver</strong> mobile apps to the Play Store and App Store:</p><p>Additionally, while less common, you may choose to publish the <strong>Admin Panel</strong> and <strong>Partnership App</strong> to app stores. However, due to their limited in-team usage, store approval might not be guaranteed. For these apps, alternative distribution methods, such as private app sharing or internal organization tools, are often preferred as they are not client-facing.</p><ul><li><p>Flutter source code is provided</p></li><li><p>Firebase setup, app configuration, and build steps are required</p></li><li><p><a href="./deployment-options-play-store.html">Deploy to Google&#39;s Play Store</a></p></li><li><p><a href="./deployment-options-app-store.html">Deploy to Apple&#39;s App Store</a></p></li></ul><blockquote><p>🛠️ Under our <strong>Pro Plus plan</strong>, we can help you publish these apps under your own developer accounts.</p></blockquote><h2 id="🔒-domain-ssl" tabindex="-1">🔒 Domain &amp; SSL <a class="header-anchor" href="#🔒-domain-ssl" aria-label="Permalink to &quot;🔒 Domain &amp; SSL&quot;">​</a></h2><p>For a secure, production-ready deployment, you&#39;ll need to configure your domain and SSL certificates.</p><p>➡️ Refer to: <a href="./https-and-ssl-setup.html">Custom Domain and SSL Setup</a></p>',27)]))}const h=o(n,[["render",i]]);export{m as __pageData,h as default};
